const inputURL=document.querySelector("input#inputURL"),buttonGuardar=document.querySelector("button");function mostrarToast(t,e){Swal.fire({toast:!0,position:"top-end",showConfirmButton:!1,timer:2800,timerProgressBar:!0,theme:"dark",icon:t,text:e.trim()})}function obtenerLS(){return localStorage.getItem("URLproductos")||""}function crearLS(){inputURL.value.trim().length>0?(localStorage.setItem("URLproductos",inputURL.value.trim()),mostrarToast("success","Se ha guardado el endpoint correctamente.")):mostrarToast("warning","Debes agregar un endpoint válido.")}inputURL.value=obtenerLS(),buttonGuardar.addEventListener("click",(()=>crearLS()));